const inputItems = $('Normalize Tender Records').all();

return inputItems.map((item) => {
  const tender = item.json;

  const ai_input_text = `
Tender ID: ${tender.tender_id || ""}
Title: ${tender.tender_title || ""}
Description: ${tender.tender_description || ""}
Authority: ${tender.authority_name || ""}
Category: ${tender.category || ""}
State: ${tender.state || ""}
City: ${tender.city || ""}
Published Date: ${tender.published_date || ""}
Bid Due Date: ${tender.bid_due_date || ""}
Estimated Value: ${tender.estimated_value || ""}
EMD Amount: ${tender.emd_amount || ""}
Document Fee: ${tender.document_fee || ""}
Source URL: ${tender.source_url || ""}
PDF URL: ${tender.pdf_url || ""}

Return strictly in JSON format with these top level keys only:
eligibility_summary
ai_summary
checklist_items
match_score

Rules:
1. eligibility_summary must be a short clear summary of likely eligibility requirements based on the tender details.
2. ai_summary must be a short business summary for bid preparation.
3. checklist_items must be an array of objects.
4. Each checklist_items object must contain:
   task_name
   task_description
   priority
   due_date
   owner
   status
   notes
5. match_score must be a number from 1 to 100.
6. Do not include markdown.
7. Do not include code fences.
8. Do not include any text before or after the JSON.
`.trim();

  return {
    json: {
      tender_id: tender.tender_id || "",
      source_name: tender.source_name || "",
      tender_title: tender.tender_title || "",
      tender_description: tender.tender_description || "",
      authority_name: tender.authority_name || "",
      category: tender.category || "",
      state: tender.state || "",
      city: tender.city || "",
      published_date: tender.published_date || "",
      bid_due_date: tender.bid_due_date || "",
      estimated_value: tender.estimated_value || 0,
      emd_amount: tender.emd_amount || 0,
      document_fee: tender.document_fee || 0,
      source_url: tender.source_url || "",
      pdf_url: tender.pdf_url || "",
      duplicate_key: `${tender.tender_id || ""}_${tender.bid_due_date || ""}`,
      checklist_status: "Pending",
      alert_sent: false,
      created_at: new Date().toISOString(),
      updated_at: new Date().toISOString(),
      ai_input_text
    }
  };
});

const items = $input.all();

return items.map((item) => {
  const rawText = item.json.content?.parts?.[0]?.text || "{}";

  let parsed;
  try {
    parsed = JSON.parse(rawText);
  } catch (error) {
    parsed = {
      eligibility_summary: "",
      ai_summary: "",
      match_score: 0,
      checklist_items: [],
      parsing_error: error.message,
      raw_output: rawText
    };
  }

  return {
    json: {
      ...item.json,
      eligibility_summary: parsed.eligibility_summary || "",
      ai_summary: parsed.ai_summary || "",
      match_score: parsed.match_score || 0,
      checklist_items: Array.isArray(parsed.checklist_items) ? parsed.checklist_items : [],
      raw_ai_output: rawText
    }
  };
});

const inputItems = $input.all();
const output = [];

for (const item of inputItems) {
  const tender = item.json;
  const checklistItems = Array.isArray(tender.checklist_items) ? tender.checklist_items : [];

  checklistItems.forEach((checklist, index) => {
    output.push({
      json: {
        checklist_id: `${tender.tender_id}-CHK-${index + 1}`,
        tender_id: tender.tender_id || "",
        tender_title: tender.tender_title || "",
        authority_name: tender.authority_name || "",
        category: tender.category || "",
        source_url: tender.source_url || "",
        pdf_url: tender.pdf_url || "",
        bid_due_date: tender.bid_due_date || "",
        task_name: checklist.task_name || "",
        task_description: checklist.task_description || "",
        owner: checklist.owner || "Bid Team",
        priority: checklist.priority || "Medium",
        due_date: checklist.due_date || tender.bid_due_date || "",
        status: checklist.status || "Pending",
        notes: checklist.notes || "",
        created_at: new Date().toISOString()
      }
    });
  });
}

return output;

